import{_ as a,c as s,o as i,a1 as e}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"7 阶段流水线全览：Bootstrap 到 Preview 完整流程详解 | AI App Factory 教程","description":"学习 AI App Factory 的完整流水线，从 Bootstrap 结构化产品想法到 Preview 生成部署指南，掌握检查点、权限控制、失败处理机制。","frontmatter":{"title":"7 阶段流水线全览：Bootstrap 到 Preview 完整流程详解 | AI App Factory 教程","sidebarTitle":"7 阶段流水线全览","subtitle":"7 阶段流水线概览","description":"学习 AI App Factory 的完整流水线，从 Bootstrap 结构化产品想法到 Preview 生成部署指南，掌握检查点、权限控制、失败处理机制。","tags":["流水线","Sisyphus","Agent"],"prerequisite":["start-init-project"],"order":40},"headers":[],"relativePath":"zh/hyz1992/agent-app-factory/start/pipeline-overview/index.md","filePath":"zh/hyz1992/agent-app-factory/start/pipeline-overview/index.md"}'),o={name:"zh/hyz1992/agent-app-factory/start/pipeline-overview/index.md"};function d(n,t,r,l,p,c){return i(),s("div",null,[...t[0]||(t[0]=[e(`<h1 id="_7-阶段流水线概览" tabindex="-1">7 阶段流水线概览 <a class="header-anchor" href="#_7-阶段流水线概览" aria-label="Permalink to &quot;7 阶段流水线概览&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解 7 个阶段流水线的完整流程和每个阶段的职责</li><li>知道每个阶段的输入、输出和退出条件</li><li>了解检查点机制如何保证质量</li><li>理解 Sisyphus 调度器如何协调 Agent 执行</li><li>掌握权限矩阵如何防止 Agent 越权</li><li>学会利用&quot;新建会话继续&quot;节省 Token</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>流水线是什么？</strong></p><p>AI App Factory 的流水线是一条自动化的生产线，将你的产品想法一步步转化为可运行的应用。就像工厂生产线一样，原料（产品想法）经过 7 个工序（阶段），最终产出成品（完整应用）。</p><p>每个工序由专门的 Agent 负责，他们各司其职，互不干扰：</p><table tabindex="0"><thead><tr><th>阶段</th><th>Agent</th><th>职责</th><th>产出</th></tr></thead><tbody><tr><td>Bootstrap</td><td>Bootstrap Agent</td><td>深入挖掘产品想法</td><td><code>input/idea.md</code></td></tr><tr><td>PRD</td><td>PRD Agent</td><td>生成产品需求文档</td><td><code>artifacts/prd/prd.md</code></td></tr><tr><td>UI</td><td>UI Agent</td><td>设计界面和原型</td><td><code>artifacts/ui/ui.schema.yaml</code> + 预览页面</td></tr><tr><td>Tech</td><td>Tech Agent</td><td>设计技术架构</td><td><code>artifacts/tech/tech.md</code> + Prisma Schema</td></tr><tr><td>Code</td><td>Code Agent</td><td>生成可运行代码</td><td><code>artifacts/backend/</code> + <code>artifacts/client/</code></td></tr><tr><td>Validation</td><td>Validation Agent</td><td>验证代码质量</td><td><code>artifacts/validation/report.md</code></td></tr><tr><td>Preview</td><td>Preview Agent</td><td>生成部署指南</td><td><code>artifacts/preview/README.md</code></td></tr></tbody></table><p><strong>关键特性</strong></p><ol><li><strong>检查点机制</strong>：每个阶段完成后暂停，等待你确认后再继续</li><li><strong>权限隔离</strong>：每个 Agent 只能读写授权目录，防止污染</li><li><strong>失败可回滚</strong>：阶段失败时自动重试，连续失败则回滚到上一个成功检查点</li><li><strong>上下文优化</strong>：支持在新会话中继续执行，节省 Token</li></ol><h2 id="流水线全览" tabindex="-1">流水线全览 <a class="header-anchor" href="#流水线全览" aria-label="Permalink to &quot;流水线全览&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Bootstrap&lt;br/&gt;结构化产品想法] --&gt;|idea.md| B[PRD&lt;br/&gt;生成需求文档]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|prd.md| C[UI&lt;br/&gt;设计界面原型]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|ui.schema.yaml| D[Tech&lt;br/&gt;设计技术架构]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|tech.md + schema.prisma| E[Code&lt;br/&gt;生成可运行代码]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt;|backend + client| F[Validation&lt;br/&gt;验证代码质量]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt;|验证报告| G[Preview&lt;br/&gt;生成部署指南]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e0f2fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#f0fdf4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#fef3c7</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#ede9fe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fce7f3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style F fill:#dbeafe</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#d1fae5</span></span></code></pre></div><p><strong>流水线执行规则</strong></p><div class="tip custom-block"><p class="custom-block-title">执行规则</p><ol><li><strong>严格顺序</strong>：必须从 Bootstrap 开始，按顺序执行到 Preview，不可跳过或并行</li><li><strong>单 Agent 激活</strong>：同一时刻只能有一个 Agent 在工作</li><li><strong>不可回溯</strong>：已确认的产物不能修改，只能重新执行该阶段</li></ol><p>注意：这些是流水线的执行规则，不等于检查点选项的数量。每个阶段完成后，Sisyphus 会提供 5 个检查点选项（详见下方&quot;检查点机制&quot;章节）。</p></div><h2 id="各阶段详解" tabindex="-1">各阶段详解 <a class="header-anchor" href="#各阶段详解" aria-label="Permalink to &quot;各阶段详解&quot;">​</a></h2><h3 id="阶段-1-bootstrap-结构化产品想法" tabindex="-1">阶段 1：Bootstrap - 结构化产品想法 <a class="header-anchor" href="#阶段-1-bootstrap-结构化产品想法" aria-label="Permalink to &quot;阶段 1：Bootstrap - 结构化产品想法&quot;">​</a></h3><p><strong>做什么？</strong></p><p>将你提供的自然语言产品描述转化为结构化的文档，深入挖掘问题、用户、价值和假设。</p><p><strong>为什么重要？</strong></p><p>清晰的产品定义是整个流水线的基础。如果这一步没做好，后续所有阶段都会偏离方向。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td>用户自然语言描述</td><td>例如：&quot;我想做一个记账应用&quot;</td></tr><tr><td>输出</td><td><code>input/idea.md</code></td><td>结构化的产品想法文档</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] <code>idea.md</code> 存在</li><li>[ ] 描述了一个连贯的产品想法</li><li>[ ] Agent 使用了 <code>superpowers:brainstorm</code> 技能深入挖掘</li></ul><p><strong>强制技能使用</strong></p><div class="warning custom-block"><p class="custom-block-title">必须使用 superpowers:brainstorm</p><p>Bootstrap 阶段必须使用 <code>superpowers:brainstorm</code> 技能进行深入挖掘，如果 Agent 没有提及使用该技能，产物会被拒绝，要求重新执行。</p></div><h3 id="阶段-2-prd-生成产品需求文档" tabindex="-1">阶段 2：PRD - 生成产品需求文档 <a class="header-anchor" href="#阶段-2-prd-生成产品需求文档" aria-label="Permalink to &quot;阶段 2：PRD - 生成产品需求文档&quot;">​</a></h3><p><strong>做什么？</strong></p><p>将结构化的产品想法转化为 MVP 级的产品需求文档，明确功能范围、非目标和用户故事。</p><p><strong>为什么重要？</strong></p><p>PRD 是设计和开发的&quot;合同&quot;，明确了&quot;做什么&quot;和&quot;不做什么&quot;，防止范围蔓延。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>input/idea.md</code></td><td>Bootstrap 阶段输出的结构化想法</td></tr><tr><td>输出</td><td><code>artifacts/prd/prd.md</code></td><td>MVP 级产品需求文档</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] PRD 包含目标用户</li><li>[ ] PRD 定义了 MVP 范围</li><li>[ ] PRD 列出了非目标</li><li>[ ] PRD 不包含任何技术实现细节</li></ul><p><strong>注意：PRD 不包含技术细节</strong></p><p>PRD 应该描述&quot;用户需要什么&quot;，而不是&quot;如何实现&quot;。技术实现细节由 Tech 和 Code 阶段负责。</p><h3 id="阶段-3-ui-设计界面与原型" tabindex="-1">阶段 3：UI - 设计界面与原型 <a class="header-anchor" href="#阶段-3-ui-设计界面与原型" aria-label="Permalink to &quot;阶段 3：UI - 设计界面与原型&quot;">​</a></h3><p><strong>做什么？</strong></p><p>基于 PRD 设计 UI 结构、配色方案，并生成可在浏览器中预览的 HTML 原型。</p><p><strong>为什么重要？</strong></p><p>可视化设计让团队和早期用户直观理解产品形态，减少开发返工。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>artifacts/prd/prd.md</code></td><td>PRD 文档</td></tr><tr><td>输出</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI 结构定义</td></tr><tr><td>输出</td><td><code>artifacts/ui/preview.web/index.html</code></td><td>可预览的 HTML 原型</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] <code>ui.schema.yaml</code> 存在</li><li>[ ] 页面数量不超过 3</li><li>[ ] 预览页面可在浏览器中打开</li><li>[ ] Agent 使用了 <code>ui-ux-pro-max</code> 技能</li></ul><p><strong>强制技能使用</strong></p><div class="warning custom-block"><p class="custom-block-title">必须使用 ui-ux-pro-max</p><p>UI 阶段必须使用 <code>ui-ux-pro-max</code> 技能生成专业的设计系统，该技能包含 67 种样式、96 种调色板和 100 条行业规则。</p></div><h3 id="阶段-4-tech-设计技术架构" tabindex="-1">阶段 4：Tech - 设计技术架构 <a class="header-anchor" href="#阶段-4-tech-设计技术架构" aria-label="Permalink to &quot;阶段 4：Tech - 设计技术架构&quot;">​</a></h3><p><strong>做什么？</strong></p><p>设计最小可行的技术架构和数据模型，选择技术栈，定义 API 端点。</p><p><strong>为什么重要？</strong></p><p>技术架构决定了代码的可维护性、扩展性和性能。过度设计会导致开发困难，设计不足则无法支撑需求。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>artifacts/prd/prd.md</code></td><td>PRD 文档</td></tr><tr><td>输出</td><td><code>artifacts/tech/tech.md</code></td><td>技术架构文档</td></tr><tr><td>输出</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>Prisma 数据模型</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] 技术栈明确声明</li><li>[ ] 数据模型与 PRD 一致</li><li>[ ] 未进行过早优化或过度设计</li></ul><p><strong>技术栈默认选择</strong></p><ul><li>后端：Node.js + Express + Prisma</li><li>数据库：SQLite（开发）/ PostgreSQL（生产）</li><li>前端：React Native + Expo</li></ul><h3 id="阶段-5-code-生成可运行代码" tabindex="-1">阶段 5：Code - 生成可运行代码 <a class="header-anchor" href="#阶段-5-code-生成可运行代码" aria-label="Permalink to &quot;阶段 5：Code - 生成可运行代码&quot;">​</a></h3><p><strong>做什么？</strong></p><p>根据 UI Schema、Tech 设计和 Prisma Schema 生成完整的前后端代码、测试、配置和文档。</p><p><strong>为什么重要？</strong></p><p>这是&quot;从想法到应用&quot;的关键一步，生成的代码是可运行的、生产就绪的。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>artifacts/ui/ui.schema.yaml</code></td><td>UI 结构定义</td></tr><tr><td>输入</td><td><code>artifacts/tech/tech.md</code></td><td>技术架构文档</td></tr><tr><td>输入</td><td><code>artifacts/backend/prisma/schema.prisma</code></td><td>数据模型</td></tr><tr><td>输出</td><td><code>artifacts/backend/</code></td><td>后端代码（Express + Prisma）</td></tr><tr><td>输出</td><td><code>artifacts/client/</code></td><td>前端代码（React Native）</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] 后端可启动且无重大错误</li><li>[ ] 客户端可渲染并访问</li><li>[ ] 未引入额外的认证或无关功能</li></ul><p><strong>生成的内容</strong></p><p>Code Agent 会生成以下内容：</p><p><strong>后端</strong>：</p><ul><li>Express 服务器 + 路由</li><li>Prisma ORM + 数据模型</li><li>单元测试和集成测试（Vitest）</li><li>API 文档（Swagger/OpenAPI）</li><li>种子数据（<code>prisma/seed.ts</code>）</li><li>Docker 配置</li><li>日志和监控</li></ul><p><strong>前端</strong>：</p><ul><li>React Native 页面和组件</li><li>React Navigation 路由</li><li>单元测试（Jest + React Testing Library）</li><li>环境配置</li></ul><div class="info custom-block"><p class="custom-block-title">为什么不生成认证功能？</p><p>AI App Factory 聚焦 MVP，默认不生成认证、授权等复杂功能。这些功能可以在后续迭代中添加。</p></div><h3 id="阶段-6-validation-验证代码质量" tabindex="-1">阶段 6：Validation - 验证代码质量 <a class="header-anchor" href="#阶段-6-validation-验证代码质量" aria-label="Permalink to &quot;阶段 6：Validation - 验证代码质量&quot;">​</a></h3><p><strong>做什么？</strong></p><p>验证生成的代码能否正常安装依赖、通过类型检查、符合代码规范。</p><p><strong>为什么重要？</strong></p><p>在运行代码前发现问题，避免部署后才发现错误，节省调试时间。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>artifacts/backend/</code></td><td>后端代码</td></tr><tr><td>输入</td><td><code>artifacts/client/</code></td><td>前端代码</td></tr><tr><td>输出</td><td><code>artifacts/validation/report.md</code></td><td>验证报告</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] 验证报告已生成</li><li>[ ] 后端依赖可正常解析</li><li>[ ] 前端依赖可正常解析</li><li>[ ] TypeScript 编译无严重错误</li><li>[ ] Prisma schema 验证通过</li></ul><p><strong>验证内容</strong></p><p>Validation Agent 会检查：</p><ol><li><strong>依赖解析</strong>：<code>npm install</code> 是否成功</li><li><strong>类型检查</strong>：<code>tsc --noEmit</code> 是否通过</li><li><strong>代码规范</strong>：是否符合 <code>policies/code-standards.md</code></li><li><strong>Prisma Schema</strong>：<code>prisma validate</code> 是否通过</li><li><strong>测试通过率</strong>：测试是否存在且能执行</li></ol><p><strong>失败处理</strong></p><p>如果验证失败，Validation Agent 会生成详细的错误报告，指出具体问题和修复建议。</p><h3 id="阶段-7-preview-生成部署指南" tabindex="-1">阶段 7：Preview - 生成部署指南 <a class="header-anchor" href="#阶段-7-preview-生成部署指南" aria-label="Permalink to &quot;阶段 7：Preview - 生成部署指南&quot;">​</a></h3><p><strong>做什么？</strong></p><p>汇总所有产物，生成完整的运行说明、部署配置和演示流程文档。</p><p><strong>为什么重要？</strong></p><p>这是流水线的最后一环，让你能快速运行和部署生成的应用。</p><p><strong>输入和输出</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td>输入</td><td><code>artifacts/backend/</code></td><td>后端代码</td></tr><tr><td>输入</td><td><code>artifacts/client/</code></td><td>前端代码</td></tr><tr><td>输出</td><td><code>artifacts/preview/README.md</code></td><td>完整运行说明</td></tr><tr><td>输出</td><td><code>artifacts/preview/GETTING_STARTED.md</code></td><td>快速启动指南</td></tr></tbody></table><p><strong>退出条件</strong></p><ul><li>[ ] README 包含安装步骤</li><li>[ ] README 包含运行命令</li><li>[ ] README 列出访问地址和演示流程</li></ul><p><strong>生成的内容</strong></p><p>Preview Agent 会生成：</p><ul><li>本地运行说明（Web、iOS、Android）</li><li>Docker 部署配置（<code>docker-compose.yml</code>）</li><li>CI/CD 配置参考（GitHub Actions）</li><li>Git Hooks 配置参考（Husky）</li><li>数据库迁移指南（SQLite → PostgreSQL）</li></ul><h2 id="检查点机制" tabindex="-1">检查点机制 <a class="header-anchor" href="#检查点机制" aria-label="Permalink to &quot;检查点机制&quot;">​</a></h2><p><strong>什么是检查点？</strong></p><p>每个阶段完成后，流水线会暂停，向你展示生成的产物列表，让你确认是否符合预期。如果不符合，你可以选择&quot;重试&quot;或&quot;修改后重新运行&quot;。</p><p><strong>为什么需要检查点？</strong></p><ul><li><strong>防止错误累积</strong>：早期的问题如果不在当前阶段解决，后续阶段会放大错误</li><li><strong>保证质量</strong>：每个阶段都确保输出符合预期，避免生成不可用的代码</li><li><strong>灵活控制</strong>：你可以在任意检查点暂停、重试或修改输入</li></ul><p><strong>检查点选项</strong></p><p>每个阶段完成后，Sisyphus 调度器会展示以下选项：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────┬──────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 选项 │ 说明                                                  │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  1   │ 继续下一阶段（同一会话）                               │</span></span>
<span class="line"><span>│      │ 我将继续执行 [下一阶段名称] 阶段                        │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  2   │ 新建会话继续 ⭐ 推荐选项，节省 Token                   │</span></span>
<span class="line"><span>│      │ 在新的命令行窗口中执行：factory continue               │</span></span>
<span class="line"><span>│      │ （会自动启动新的 Claude Code 窗口并继续流水线）        │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  3   │ 重跑该阶段                                             │</span></span>
<span class="line"><span>│      │ 重新执行 [当前阶段名称] 阶段                           │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  4   │ 修改产物后重新运行                                     │</span></span>
<span class="line"><span>│      │ 修改 [某个输入文件] 后重新执行                         │</span></span>
<span class="line"><span>├──────┼──────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  5   │ 暂停流水线                                             │</span></span>
<span class="line"><span>│      │ 保存当前进度，稍后继续                                 │</span></span>
<span class="line"><span>└──────┴──────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>推荐做法</strong></p><div class="tip custom-block"><p class="custom-block-title">选择&quot;新建会话继续&quot;节省 Token</p><p>每个阶段完成后，推荐选择&quot;新建会话继续&quot;（选项 2）：</p><ol><li>在新的命令行窗口执行 <code>factory continue</code></li><li>命令会自动启动新的 Claude Code 窗口</li><li>每个阶段独享干净的上下文，避免 Token 累积</li></ol></div><h2 id="权限矩阵" tabindex="-1">权限矩阵 <a class="header-anchor" href="#权限矩阵" aria-label="Permalink to &quot;权限矩阵&quot;">​</a></h2><p><strong>为什么需要权限隔离？</strong></p><p>如果 Agent 可以随意读写任何目录，可能会导致：</p><ul><li>Bootstrap Agent 意外修改了已完成的 PRD</li><li>Code Agent 意外删除了 UI 设计</li><li>Validation Agent 误改了后端代码</li></ul><p><strong>能力边界矩阵</strong></p><p>Sisyphus 调度器会在每个阶段执行前后检查 Agent 的权限：</p><table tabindex="0"><thead><tr><th>Agent</th><th>可读取</th><th>可写入</th></tr></thead><tbody><tr><td>bootstrap</td><td>无</td><td><code>input/</code></td></tr><tr><td>prd</td><td><code>input/</code></td><td><code>artifacts/prd/</code></td></tr><tr><td>ui</td><td><code>artifacts/prd/</code></td><td><code>artifacts/ui/</code></td></tr><tr><td>tech</td><td><code>artifacts/prd/</code></td><td><code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td></tr><tr><td>code</td><td><code>artifacts/ui/</code>, <code>artifacts/tech/</code>, <code>artifacts/backend/prisma/</code></td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td></tr><tr><td>validation</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/validation/</code></td></tr><tr><td>preview</td><td><code>artifacts/backend/</code>, <code>artifacts/client/</code></td><td><code>artifacts/preview/</code></td></tr></tbody></table><p><strong>越权处理</strong></p><p>如果 Agent 写入了未授权目录，Sisyphus 调度器会将文件移动到 <code>artifacts/_untrusted/&lt;stage-id&gt;/</code>，暂停流水线并报告。</p><div class="warning custom-block"><p class="custom-block-title">越权例子</p><p>假设 PRD Agent 写入了 <code>artifacts/ui/ui.schema.yaml</code>（这不是它的权限范围），调度器会：</p><ol><li>将文件移动到 <code>artifacts/_untrusted/prd/ui.schema.yaml</code></li><li>暂停流水线</li><li>报告：检测到越权写入，请人工处理</li></ol></div><h2 id="失败处理" tabindex="-1">失败处理 <a class="header-anchor" href="#失败处理" aria-label="Permalink to &quot;失败处理&quot;">​</a></h2><p><strong>什么算失败？</strong></p><ul><li>输出文件缺失</li><li>产物内容不符合 <code>exit_criteria</code></li><li>Agent 写入了未授权目录</li><li>脚本错误或无法读取输入</li></ul><p><strong>默认处理策略</strong></p><ol><li><strong>自动重试</strong>：每个阶段允许自动重试一次</li><li><strong>失败归档</strong>：失败的产物移动到 <code>artifacts/_failed/&lt;stage-id&gt;/</code></li><li><strong>暂停流水线</strong>：连续失败两次后，等待人工介入</li><li><strong>回滚机制</strong>：回滚到最近成功的检查点重新执行</li></ol><div class="tip custom-block"><p class="custom-block-title">人工介入后的处理</p><p>如果连续失败两次，你可以：</p><ol><li>修改输入文件（如 <code>input/idea.md</code>）</li><li>调整 Agent 提示词</li><li>修复权限问题</li><li>执行 <code>factory run [stage]</code> 从该阶段重新开始</li></ol></div><h2 id="状态管理" tabindex="-1">状态管理 <a class="header-anchor" href="#状态管理" aria-label="Permalink to &quot;状态管理&quot;">​</a></h2><p><strong>状态文件</strong></p><p>流水线的所有状态都保存在 <code>.factory/state.json</code>，包括：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;waiting_for_confirmation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;current_stage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;prd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;completed_stages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bootstrap&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;started_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;last_updated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-01-29T10:30:00Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>状态机</strong></p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th><th>触发条件</th></tr></thead><tbody><tr><td>idle</td><td>未启动</td><td>等待 <code>factory run</code></td></tr><tr><td>running</td><td>正在执行</td><td>开始执行某个 Stage</td></tr><tr><td>waiting_for_confirmation</td><td>等待确认</td><td>阶段完成</td></tr><tr><td>paused</td><td>已暂停</td><td>用户选择暂停</td></tr><tr><td>failed</td><td>失败需介入</td><td>连续失败或越权操作</td></tr></tbody></table><p>只有 Sisyphus 调度器有权限更新状态。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="常见错误-1-bootstrap-阶段未使用-brainstorm-技能" tabindex="-1">常见错误 1：Bootstrap 阶段未使用 brainstorm 技能 <a class="header-anchor" href="#常见错误-1-bootstrap-阶段未使用-brainstorm-技能" aria-label="Permalink to &quot;常见错误 1：Bootstrap 阶段未使用 brainstorm 技能&quot;">​</a></h3><p><strong>现象</strong>：Sisyphus 拒绝接受 <code>input/idea.md</code>，提示&quot;检测到未使用 superpowers:brainstorm 技能&quot;。</p><p><strong>原因</strong>：Bootstrap Agent 没有使用 <code>superpowers:brainstorm</code> 技能深入挖掘产品想法。</p><p><strong>解决方法</strong>：在确认产物时，选择&quot;重跑该阶段&quot;，明确要求 Agent 使用 <code>superpowers:brainstorm</code> 技能。</p><h3 id="常见错误-2-ui-阶段设计平庸" tabindex="-1">常见错误 2：UI 阶段设计平庸 <a class="header-anchor" href="#常见错误-2-ui-阶段设计平庸" aria-label="Permalink to &quot;常见错误 2：UI 阶段设计平庸&quot;">​</a></h3><p><strong>现象</strong>：生成的 UI 设计千篇一律，都是紫色渐变、Inter 字体。</p><p><strong>原因</strong>：UI Agent 没有使用 <code>ui-ux-pro-max</code> 技能。</p><p><strong>解决方法</strong>：在确认产物时，选择&quot;重跑该阶段&quot;，明确要求 Agent 使用 <code>ui-ux-pro-max</code> 技能，并指定一个鲜明的审美方向（如&quot;赛博朋克&quot;、&quot;极简主义&quot;）。</p><h3 id="常见错误-3-code-阶段生成了认证功能" tabindex="-1">常见错误 3：Code 阶段生成了认证功能 <a class="header-anchor" href="#常见错误-3-code-阶段生成了认证功能" aria-label="Permalink to &quot;常见错误 3：Code 阶段生成了认证功能&quot;">​</a></h3><p><strong>现象</strong>：生成的后端代码包含了 JWT 认证、用户登录等复杂功能。</p><p><strong>原因</strong>：Code Agent 超出了 MVP 范围。</p><p><strong>解决方法</strong>：修改 PRD，明确列出&quot;非目标&quot;（如&quot;不支持用户登录&quot;、&quot;不支持多人协作&quot;），然后重新执行 Code 阶段。</p><h3 id="常见错误-4-token-消耗过大" tabindex="-1">常见错误 4：Token 消耗过大 <a class="header-anchor" href="#常见错误-4-token-消耗过大" aria-label="Permalink to &quot;常见错误 4：Token 消耗过大&quot;">​</a></h3><p><strong>现象</strong>：流水线执行到后期，Token 消耗激增，AI 助手响应变慢。</p><p><strong>原因</strong>：在同一会话中执行多个阶段，上下文不断累积。</p><p><strong>解决方法</strong>：<strong>始终选择&quot;新建会话继续&quot;</strong>（选项 2），让每个阶段独享干净的上下文。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>流水线包含 7 个阶段：Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>每个阶段完成后暂停确认，确保输出符合预期</li><li>Sisyphus 调度器协调 Agent 执行，管理状态和权限</li><li>能力边界矩阵防止 Agent 越权，保证职责分离</li><li>选择&quot;新建会话继续&quot;可以大幅节省 Token</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../platforms/claude-code/">Claude Code 集成指南</a></strong>。</p><p>你会学到：</p><ul><li>如何配置 Claude Code 权限</li><li>如何运行流水线</li><li>Claude Code 的最佳实践</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>流水线定义</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-111</td></tr><tr><td>调度器核心</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-302</td></tr><tr><td>项目 README</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>1-253</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li>流水线模式：<code>checkpoint</code>（检查点模式，每个阶段暂停确认）</li></ul><p><strong>关键 Agent 定义</strong>：</p><ul><li><strong>Bootstrap Agent</strong>：使用 <code>superpowers:brainstorm</code> 技能，生成 <code>input/idea.md</code></li><li><strong>PRD Agent</strong>：读取 <code>input/idea.md</code>，生成 <code>artifacts/prd/prd.md</code></li><li><strong>UI Agent</strong>：使用 <code>ui-ux-pro-max</code> 技能，生成 <code>artifacts/ui/ui.schema.yaml</code> 和预览页面</li><li><strong>Tech Agent</strong>：生成 <code>artifacts/tech/tech.md</code> 和 <code>artifacts/backend/prisma/schema.prisma</code></li><li><strong>Code Agent</strong>：根据 UI、Tech、Schema 生成 <code>artifacts/backend/</code> 和 <code>artifacts/client/</code></li><li><strong>Validation Agent</strong>：验证代码质量，生成 <code>artifacts/validation/report.md</code></li><li><strong>Preview Agent</strong>：生成 <code>artifacts/preview/README.md</code></li></ul></details>`,158)])])}const u=a(o,[["render",d]]);export{g as __pageData,u as default};
